INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-94737317-moex-00562', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於修憲程序，下列敘述何者錯誤？', '["以公民投票法之創制程序提出修憲案", "經立法院決議提出修憲案", "經公民複決程序通過修憲案", "經立法院修憲委員會討論並提出修憲案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00563', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '有關自治法規的敘述，下列何者正確？', '["自治法規經地方立法機關通過，並由各該行政機關公布者，稱自治規則", "直轄市法規、縣（市）規章就違反地方自治事項之行政業務者，得規定處以罰鍰或其他種類之行政 罰，其額度並無限制", "自治條例經各該地方立法機關議決後，如規定有罰則時，應分別報經行政院、中央各該主管機關核 定後發布", "直轄市自治規則，除法律或基於法律授權之法規另有規定外，應於發布後函報立法院備查，並函送 各該地方立法機關查照"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00564', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '地方制度法關於自治條例的規定，下列敘述何者錯誤？', '["地方行政機關得對地方立法機關所議決的自治條例提起覆議", "自治條例制定有罰則者，以罰鍰為限，不得處以勒令停工停業等不利處分", "自治規則有無牴觸該自治團體自治條例發生疑義時，得聲請司法院解釋之", "直轄市自治條例發布後，應報中央各該主管機關轉行政院備查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00565', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '普通刑法與陸海空軍刑法皆有處罰竊取行為之規定。現役軍人竊取彈藥，優先適用後者。此為何種法 律適用原則？', '["從新從優原則", "罪刑法定原則", "特別法優於普通法原則", "一罪不二罰原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00566', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '下列選項各罪中所指的「公務員」，何者不是「構成犯罪」之行為人身分要素？', '["刑法第123條的準賄賂罪", "刑法第125條的濫用職權追訴罪", "刑法第135條的妨害公務罪", "刑法第213條的公務員登載不實罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00567', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '甲、乙、丙、丁四人基於共同殺A的意思約定同時向A開槍，結果A僅被甲開槍射出的子彈擊中要 害而死亡。乙雖然有開槍，但子彈未擊中任何東西。丙因臨時心生恐懼，不敢扣下扳機。丁開槍但子 彈誤中A旁邊的古董花瓶，花瓶當場粉碎。下列關於甲乙丙丁四人刑事責任之敘述，何者正確？', '["乙開槍未擊中A，不成立殺人既遂罪之共同正犯", "丁開槍擊中花瓶，成立殺人既遂罪之共同正犯", "甲開槍擊中A，成立普通毀損罪之共同正犯", "丙未扣下扳機，不成立殺人既遂罪之共同正犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00568', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依據消費者保護法，關於消費訴訟的敘述，下列何者正確？', '["消費者保護團體許可設立至少3年以上，置有消費者保護專門人員，且申請行政院評定優良者，得 以自己之名義，提起消費者團體損害賠償訴訟", "消費者保護團體對於同一之原因事件，致使眾多消費者受害時，得受讓15人以上消費者損害賠償 請求權後，以自己名義，提起訴訟", "法院為企業經營者敗訴之判決時，可依職權宣告為減免擔保之假執行", "於消費者保護法第50條消費者團體訴訟中，消費者損害賠償請求權之時效利益，應依團體中之最 有利者統一計算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00569', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '某國立大學碩士班學生甲依學位授予法撰寫完成碩士論文（以下簡稱為A論文），有關甲就A論文 所享有之著作人格權的敘述，下列何者錯誤？', '["甲就A論文享有姓名表示權，得在論文上表示其本名", "甲就其A論文享有公開發表權，故即使甲已取得學位，亦不得擅自推定甲已同意公開發表A論文", "甲就其A論文享有禁止他人以歪曲、割裂、竄改或其他方法改變其著作之內容，致損害其名譽之 權利", "甲就其A論文所享有之著作人格權，不得讓與給他人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00570', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '勞動基準法第22條關於工資給付之規定，下列敘述何者錯誤？', '["工資之給付，應以法定通用貨幣為之", "基於習慣或業務性質，得於勞動契約內訂明一部以實物給付之", "工資應全額直接給付勞工，勞雇雙方不得另作其他約定", "工資可一部以實物給付，其實物之作價應公平合理，並適合勞工及其家屬之需要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00571', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '適用勞動基準法之雇主與勞工約定試用期，下列敘述何者正確？', '["勞動基準法沒有規定試用期，但只要長度合理且經過勞資雙方同意，仍可以設定試用期。不過試用 期間因為還未正式僱用，可不給付薪資", "勞動基準法未禁止試用期，因此只要勞資雙方合意且設定期間合理，仍可設定試用期。惟勞動基準 法關於工資給付之規定屬於強制規定，因此試用期間內仍須給付全額薪資", "勞動基準法未規範試用期，因此即使經過勞資雙方同意，仍不得自行設定試用期，並為有異於其法 定的工資給付設定", "社會新鮮人因為沒有工作經驗，因此即使勞動基準法沒規定，仍可以透過勞資同意設定試用期，但 因為試用中等同職前訓練，因此不計入工作年資"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
